"""Lesson data 66-70: Johannine metaphors, Hebrews faith, Philippians joy"""
from src.tts import M, F

L66={"num":66,"intro_es":"Μάθημα ἑξήκοντα ἕξ. Lección sesenta y seis. Hoy leerás Juan tres: Nicodemo y el nuevo nacimiento. Escucha.",
"dialogue":[(F,"Ῥαββί, οἴδαμεν ὅτι ἀπὸ θεοῦ ἐλήλυθας διδάσκαλος."),(M,"Ἀμὴν ἀμὴν λέγω σοι, ἐὰν μή τις γεννηθῇ ἄνωθεν, οὐ δύναται ἰδεῖν τὴν βασιλείαν τοῦ θεοῦ.")],
"context_es":"Rabí, sabemos que has venido de Dios como maestro. De cierto te digo, si uno no nace de nuevo, no puede ver el reino de Dios.",
"vocab":[{"gr":"γεννάω","es":"engendrar, nacer","note_es":"γεννάω significa engendrar o dar a luz. γεννηθῇ es nazca, subjuntivo pasivo. Aparece noventa y siete veces. Escucha."},{"gr":"ἄνωθεν","es":"de arriba, de nuevo","note_es":"ἄνωθεν significa de arriba o de nuevo. Tiene doble sentido en Juan tres. Escucha."},{"gr":"ἀμήν","es":"de cierto, amén","note_es":"ἀμήν significa de cierto o en verdad. Jesús dice ἀμὴν ἀμήν en Juan para enfatizar. Escucha."},{"gr":"δύναται","es":"puede","note_es":"Ya conoces δύναμαι. δύναται es puede, tercera persona. Escucha."},{"gr":"ἄνω","es":"arriba","note_es":"ἄνω significa arriba. Lo opuesto de κάτω, abajo. Escucha."},{"gr":"κάτω","es":"abajo","note_es":"κάτω significa abajo. Escucha."}],
"phrases":[{"gr":"ἀμὴν ἀμὴν λέγω σοι","es":"de cierto de cierto te digo","prompt_es":"Di de cierto de cierto te digo. La fórmula solemne de Jesús en Juan."},{"gr":"ἐὰν μή τις γεννηθῇ ἄνωθεν","es":"si uno no nace de nuevo","prompt_es":"Di si uno no nace de nuevo."},{"gr":"οὐ δύναται ἰδεῖν τὴν βασιλείαν τοῦ θεοῦ","es":"no puede ver el reino de Dios","prompt_es":"Di no puede ver el reino de Dios."},{"gr":"γεννηθῆναι ἐξ ὕδατος καὶ πνεύματος","es":"nacer de agua y Espíritu","prompt_es":"Di nacer de agua y Espíritu."},{"gr":"τὸ πνεῦμα ὅπου θέλει πνεῖ","es":"el Espíritu sopla donde quiere","prompt_es":"Di el Espíritu sopla donde quiere. πνεῖ es sopla."},{"gr":"τὰ ἐπουράνια","es":"las cosas celestiales","prompt_es":"Di las cosas celestiales."}],
"recon":[{"prompt_es":"Di de cierto de cierto te digo.","answer_gr":"Ἀμὴν ἀμὴν λέγω σοι.","answer_voice":M},{"prompt_es":"Di si uno no nace de nuevo no puede ver el reino de Dios.","answer_gr":"Ἐὰν μή τις γεννηθῇ ἄνωθεν, οὐ δύναται ἰδεῖν τὴν βασιλείαν τοῦ θεοῦ.","answer_voice":M},{"prompt_es":"Di nacer de agua y Espíritu.","answer_gr":"Γεννηθῆναι ἐξ ὕδατος καὶ πνεύματος.","answer_voice":M}],
"verse":{"gr":"Ἀμὴν ἀμὴν λέγω σοι, ἐὰν μή τις γεννηθῇ ἄνωθεν, οὐ δύναται ἰδεῖν τὴν βασιλείαν τοῦ θεοῦ.","voice":M,"ref_es":"Juan tres tres:","explain_es":"De cierto te digo, si uno no nace de nuevo, no puede ver el reino de Dios. γεννηθῇ, nazca. ἄνωθεν, de nuevo o de arriba. δύναται, puede. ἰδεῖν, ver."},
"closing_es":"Aprendiste sobre el nuevo nacimiento: γεννάω nacer, ἄνωθεν de arriba, ἀμήν de cierto. Εἰρήνη σοι."}

L67={"num":67,"intro_es":"Μάθημα ἑξήκοντα ἑπτά. Lección sesenta y siete. Hoy leerás Hebreos once: la fe. Escucha.",
"dialogue":[(M,"Ἔστιν δὲ πίστις ἐλπιζομένων ὑπόστασις, πραγμάτων ἔλεγχος οὐ βλεπομένων.")],
"context_es":"La fe es la certeza de lo que se espera, la convicción de lo que no se ve. Hebreos once uno.",
"vocab":[{"gr":"ὑπόστασις","es":"certeza, sustancia","note_es":"ὑπόστασις significa certeza o sustancia. Viene de ὑπό, debajo, y ἵστημι, estar. Lo que está debajo, el fundamento. Escucha."},{"gr":"ἔλεγχος","es":"convicción, prueba","note_es":"ἔλεγχος significa convicción o prueba. Escucha."},{"gr":"πρᾶγμα","es":"cosa, asunto","note_es":"πρᾶγμα significa cosa o asunto. πραγμάτων es de las cosas, genitivo plural. Escucha."},{"gr":"ἐλπίζω","es":"esperar","note_es":"ἐλπίζω significa esperar. ἐλπιζομένων es de las cosas esperadas, participio pasivo genitivo. Escucha."},{"gr":"πίστει","es":"por fe (dativo)","note_es":"πίστει es el dativo de πίστις. Significa por fe o con fe. Hebreos once repite πίστει constantemente. Escucha."},{"gr":"μαρτυρέω","es":"testificar","note_es":"Ya conoces μαρτυρέω. ἐμαρτυρήθησαν, recibieron testimonio. Los héroes de la fe. Escucha."}],
"phrases":[{"gr":"πίστις ἐλπιζομένων ὑπόστασις","es":"fe es certeza de lo esperado","prompt_es":"Di fe es certeza de lo esperado."},{"gr":"πραγμάτων ἔλεγχος οὐ βλεπομένων","es":"convicción de lo que no se ve","prompt_es":"Di convicción de lo que no se ve."},{"gr":"πίστει Ἀβραάμ","es":"por fe Abraham","prompt_es":"Di por fe Abraham."},{"gr":"πίστει Μωϋσῆς","es":"por fe Moisés","prompt_es":"Di por fe Moisés."},{"gr":"χωρὶς πίστεως","es":"sin fe","prompt_es":"Di sin fe. χωρίς significa sin."},{"gr":"ἀδύνατον εὐαρεστῆσαι","es":"imposible agradar","prompt_es":"Di imposible agradar. Sin fe es imposible agradar a Dios."}],
"recon":[{"prompt_es":"Recita Hebreos once uno.","answer_gr":"Ἔστιν δὲ πίστις ἐλπιζομένων ὑπόστασις, πραγμάτων ἔλεγχος οὐ βλεπομένων.","answer_voice":M},{"prompt_es":"Di por fe Abraham.","answer_gr":"Πίστει Ἀβραάμ.","answer_voice":M},{"prompt_es":"Di sin fe es imposible agradar a Dios.","answer_gr":"Χωρὶς δὲ πίστεως ἀδύνατον εὐαρεστῆσαι.","answer_voice":M}],
"verse":{"gr":"Ἔστιν δὲ πίστις ἐλπιζομένων ὑπόστασις, πραγμάτων ἔλεγχος οὐ βλεπομένων.","voice":M,"ref_es":"Hebreos once uno:","explain_es":"La fe es la certeza de lo que se espera, la convicción de lo que no se ve. ὑπόστασις, certeza. ἔλεγχος, convicción. βλεπομένων, de lo visto."},
"closing_es":"Aprendiste sobre la fe: ὑπόστασις certeza, ἔλεγχος convicción, πρᾶγμα cosa, ἐλπίζω esperar. Εἰρήνη σοι."}

L68={"num":68,"intro_es":"Μάθημα ἑξήκοντα ὀκτώ. Lección sesenta y ocho. Hoy leerás Filipenses: el gozo en Cristo. Escucha.",
"dialogue":[(M,"Χαίρετε ἐν κυρίῳ πάντοτε· πάλιν ἐρῶ, χαίρετε."),(M,"Τὸ λοιπόν, ἀδελφοί, ὅσα ἐστὶν ἀληθῆ, ὅσα σεμνά, ὅσα δίκαια... ταῦτα λογίζεσθε.")],
"context_es":"Alégrense en el Señor siempre. Otra vez digo: alégrense. Por lo demás, hermanos, todo lo que es verdadero, honorable, justo, piensen en estas cosas.",
"vocab":[{"gr":"πάντοτε","es":"siempre","note_es":"πάντοτε significa siempre. Viene de πᾶς, todo, y τότε, entonces. Escucha."},{"gr":"σεμνός","es":"honorable, digno","note_es":"σεμνός significa honorable o digno de respeto. Escucha."},{"gr":"ἀρετή","es":"virtud, excelencia","note_es":"ἀρετή significa virtud o excelencia moral. Escucha."},{"gr":"ἔπαινος","es":"alabanza","note_es":"ἔπαινος significa alabanza o elogio. Escucha."},{"gr":"εἰρήνη τοῦ θεοῦ","es":"la paz de Dios","note_es":"Ya conoces εἰρήνη. ἡ εἰρήνη τοῦ θεοῦ, la paz de Dios. Escucha."},{"gr":"φρουρέω","es":"guardar, custodiar","note_es":"φρουρέω significa guardar o custodiar. La paz de Dios guardará sus corazones. Escucha."}],
"phrases":[{"gr":"χαίρετε ἐν κυρίῳ πάντοτε","es":"alégrense en el Señor siempre","prompt_es":"Di alégrense en el Señor siempre."},{"gr":"πάλιν ἐρῶ, χαίρετε","es":"otra vez digo, alégrense","prompt_es":"Di otra vez digo, alégrense."},{"gr":"ὅσα ἐστὶν ἀληθῆ","es":"todo lo que es verdadero","prompt_es":"Di todo lo que es verdadero. ὅσα significa todo lo que."},{"gr":"ταῦτα λογίζεσθε","es":"piensen en estas cosas","prompt_es":"Di piensen en estas cosas."},{"gr":"ἡ εἰρήνη τοῦ θεοῦ φρουρήσει τὰς καρδίας ὑμῶν","es":"la paz de Dios guardará sus corazones","prompt_es":"Di la paz de Dios guardará sus corazones."},{"gr":"πάντα ἰσχύω ἐν τῷ ἐνδυναμοῦντί με","es":"todo lo puedo en el que me fortalece","prompt_es":"Di todo lo puedo en el que me fortalece."}],
"recon":[{"prompt_es":"Di alégrense en el Señor siempre.","answer_gr":"Χαίρετε ἐν κυρίῳ πάντοτε.","answer_voice":M},{"prompt_es":"Di todo lo puedo en el que me fortalece.","answer_gr":"Πάντα ἰσχύω ἐν τῷ ἐνδυναμοῦντί με.","answer_voice":M},{"prompt_es":"Di piensen en estas cosas.","answer_gr":"Ταῦτα λογίζεσθε.","answer_voice":M}],
"verse":{"gr":"Πάντα ἰσχύω ἐν τῷ ἐνδυναμοῦντί με.","voice":M,"ref_es":"Filipenses cuatro trece:","explain_es":"Todo lo puedo en el que me fortalece. πάντα, todo. ἰσχύω, puedo. ἐνδυναμοῦντι, el que fortalece, participio de ἐνδυναμόω. με, me."},
"closing_es":"Aprendiste gozo: πάντοτε siempre, σεμνός honorable, ἀρετή virtud, φρουρέω guardar. Εἰρήνη σοι."}

L69={"num":69,"intro_es":"Μάθημα ἑξήκοντα ἐννέα. Lección sesenta y nueve. Hoy leerás sobre la creación nueva. Apocalipsis veintiuno. Escucha.",
"dialogue":[(M,"Ἰδοὺ καινὰ ποιῶ πάντα."),(M,"Ἐγώ εἰμι τὸ ἄλφα καὶ τὸ ὦ, ἡ ἀρχὴ καὶ τὸ τέλος.")],
"context_es":"He aquí, hago nuevas todas las cosas. Yo soy el Alfa y la Omega, el principio y el fin.",
"vocab":[{"gr":"καινός","es":"nuevo","note_es":"καινός significa nuevo. Diferente de νέος. καινός es nuevo en calidad, νέος es nuevo en tiempo. καινὰ πάντα, todas las cosas nuevas. Escucha."},{"gr":"ἄλφα","es":"alfa, primera letra","note_es":"ἄλφα es la primera letra del alfabeto griego. Escucha."},{"gr":"ὦ","es":"omega, última letra","note_es":"ὦ es la última letra del alfabeto griego. Alfa y omega, principio y fin. Escucha."},{"gr":"θρόνος","es":"trono","note_es":"θρόνος significa trono. Aparece sesenta y dos veces, especialmente en Apocalipsis. Escucha."},{"gr":"δάκρυον","es":"lágrima","note_es":"δάκρυον significa lágrima. Dios enjugará toda lágrima. Escucha."},{"gr":"νικάω","es":"vencer","note_es":"Ya conoces νικάω. ὁ νικῶν, el que vence. Escucha."}],
"phrases":[{"gr":"ἰδοὺ καινὰ ποιῶ πάντα","es":"he aquí hago nuevas todas las cosas","prompt_es":"Di he aquí hago nuevas todas las cosas."},{"gr":"ἐγώ εἰμι τὸ ἄλφα καὶ τὸ ὦ","es":"yo soy el Alfa y la Omega","prompt_es":"Di yo soy el Alfa y la Omega."},{"gr":"ἡ ἀρχὴ καὶ τὸ τέλος","es":"el principio y el fin","prompt_es":"Di el principio y el fin."},{"gr":"ἐξαλείψει πᾶν δάκρυον","es":"enjugará toda lágrima","prompt_es":"Di enjugará toda lágrima."},{"gr":"ὁ καθήμενος ἐπὶ τῷ θρόνῳ","es":"el que está sentado en el trono","prompt_es":"Di el que está sentado en el trono."},{"gr":"ὁ νικῶν κληρονομήσει ταῦτα","es":"el que venza heredará estas cosas","prompt_es":"Di el que venza heredará estas cosas."}],
"recon":[{"prompt_es":"Di he aquí hago nuevas todas las cosas.","answer_gr":"Ἰδοὺ καινὰ ποιῶ πάντα.","answer_voice":M},{"prompt_es":"Di yo soy el Alfa y la Omega.","answer_gr":"Ἐγώ εἰμι τὸ ἄλφα καὶ τὸ ὦ.","answer_voice":M},{"prompt_es":"Di enjugará toda lágrima.","answer_gr":"Ἐξαλείψει πᾶν δάκρυον.","answer_voice":M}],
"verse":{"gr":"Ἰδοὺ καινὰ ποιῶ πάντα.","voice":M,"ref_es":"Apocalipsis veintiuno cinco:","explain_es":"He aquí, hago nuevas todas las cosas. ἰδού, he aquí. καινά, nuevas. ποιῶ, hago. πάντα, todas."},
"closing_es":"Aprendiste sobre la nueva creación: καινός nuevo, θρόνος trono, δάκρυον lágrima, νικάω vencer. Εἰρήνη σοι."}

L70={"num":70,"intro_es":"Μάθημα ἑβδομήκοντα. Lección setenta. Hoy leerás el himno de Cristo en Filipenses dos. Escucha.",
"dialogue":[(M,"Ὃς ἐν μορφῇ θεοῦ ὑπάρχων οὐχ ἁρπαγμὸν ἡγήσατο τὸ εἶναι ἴσα θεῷ, ἀλλ᾽ ἑαυτὸν ἐκένωσεν μορφὴν δούλου λαβών.")],
"context_es":"El cual siendo en forma de Dios, no estimó el ser igual a Dios como cosa a que aferrarse, sino que se despojó a sí mismo tomando forma de siervo.",
"vocab":[{"gr":"μορφή","es":"forma, naturaleza","note_es":"μορφή significa forma o naturaleza esencial. ἐν μορφῇ θεοῦ, en forma de Dios. Escucha."},{"gr":"ἴσος","es":"igual","note_es":"ἴσος significa igual. ἴσα θεῷ, igual a Dios. Escucha."},{"gr":"κενόω","es":"vaciar, despojar","note_es":"κενόω significa vaciar o despojar. ἑαυτὸν ἐκένωσεν, se despojó a sí mismo. De aquí viene kenosis. Escucha."},{"gr":"ταπεινόω","es":"humillar","note_es":"ταπεινόω significa humillar. ἐταπείνωσεν ἑαυτόν, se humilló a sí mismo. Escucha."},{"gr":"ὑπερυψόω","es":"exaltar sobremanera","note_es":"ὑπερυψόω significa exaltar sobremanera. Viene de ὑπέρ, sobre, y ὑψόω, exaltar. Dios lo exaltó hasta lo sumo. Escucha."},{"gr":"γόνυ","es":"rodilla","note_es":"γόνυ significa rodilla. πᾶν γόνυ κάμψῃ, toda rodilla se doble. Escucha."}],
"phrases":[{"gr":"ἐν μορφῇ θεοῦ ὑπάρχων","es":"siendo en forma de Dios","prompt_es":"Di siendo en forma de Dios."},{"gr":"ἑαυτὸν ἐκένωσεν","es":"se despojó a sí mismo","prompt_es":"Di se despojó a sí mismo."},{"gr":"μορφὴν δούλου λαβών","es":"tomando forma de siervo","prompt_es":"Di tomando forma de siervo."},{"gr":"ἐταπείνωσεν ἑαυτόν","es":"se humilló a sí mismo","prompt_es":"Di se humilló a sí mismo."},{"gr":"ὁ θεὸς αὐτὸν ὑπερύψωσεν","es":"Dios lo exaltó sobremanera","prompt_es":"Di Dios lo exaltó sobremanera."},{"gr":"πᾶν γόνυ κάμψῃ","es":"toda rodilla se doble","prompt_es":"Di toda rodilla se doble."}],
"recon":[{"prompt_es":"Di se despojó a sí mismo tomando forma de siervo.","answer_gr":"Ἑαυτὸν ἐκένωσεν μορφὴν δούλου λαβών.","answer_voice":M},{"prompt_es":"Di se humilló a sí mismo.","answer_gr":"Ἐταπείνωσεν ἑαυτόν.","answer_voice":M},{"prompt_es":"Di Dios lo exaltó sobremanera.","answer_gr":"Ὁ θεὸς αὐτὸν ὑπερύψωσεν.","answer_voice":M}],
"verse":{"gr":"Διὸ καὶ ὁ θεὸς αὐτὸν ὑπερύψωσεν καὶ ἐχαρίσατο αὐτῷ τὸ ὄνομα τὸ ὑπὲρ πᾶν ὄνομα.","voice":M,"ref_es":"Filipenses dos nueve:","explain_es":"Por lo cual Dios lo exaltó hasta lo sumo y le dio el nombre que es sobre todo nombre. ὑπερύψωσεν, exaltó. ἐχαρίσατο, dio graciosamente. ὄνομα, nombre. ὑπέρ, sobre."},
"closing_es":"Aprendiste el himno de Cristo: μορφή forma, κενόω vaciar, ταπεινόω humillar, ὑπερυψόω exaltar. Εἰρήνη σοι."}
